    public static List<TLV> parse(String qr) {
        List<TLV> result = new ArrayList<>();
        int i = 0;

        while (i < qr.length()) {
            String tag = qr.substring(i, i + 2);
            int length = Integer.parseInt(qr.substring(i + 2, i + 4));
            String value = qr.substring(i + 4, i + 4 + length);

            List<TLV> children = null;

            if (List.of("40", "62", "64", "80").contains(tag)) {
                children = parse(value);
            }

            result.add(new TLV(tag, length, value, children));
            i += 4 + length;
        }
        return result;
    }
